 47→
 48→const APP_NAME = "Hevy Planner";
 49→
 50→export interface Env {
 51→  DB: D1Database;
 52→  ENVIRONMENT: string;
 53→  CF_ACCESS_AUD?: string;
 54→}
 55→
 56→// ──────────────────────────────────────────────────────────────────
 57→// Helpers
 58→// ──────────────────────────────────────────────────────────────────
 59→
 60→function todayString(timezone?: string): string {
 61→  if (timezone) {
 62→    try {
 63→      return new Date().toLocaleDateString("en-CA", { timeZone: timezone });
 64→    } catch { /* fall through to UTC */ }
 65→  }
 66→  return new Date().toISOString().slice(0, 10);
 67→}
 68→
 69→/** Load the subtitle from the active program, or undefined on failure. */
 70→async function loadSubtitle(db: D1Database, userId: string): Promise<string | undefined> {
 71→  try {
 72→    const prog = await loadProgram(db, userId);
 73→    return prog.meta.subtitle;
 74→  } catch {
 75→    return undefined;
 76→  }
 77→}
 78→
 79→/** Load the active program from D1 for a given user. */
 80→async function loadProgram(db: D1Database, userId: string): Promise<Program> {
 81→  const row = await getActiveProgram(db, userId);
 82→  if (!row) throw new Error("No active program found");
 83→  return JSON.parse(row.json_data) as Program;
 84→}
 85→
 86→function htmlResponse(body: string): Response {
 87→  return new Response(body, {
 88→    headers: {
 89→      "content-type": "text/html; charset=utf-8",
 90→      "cache-control": "private, no-store",
 91→      "vary": "Accept",
 92→    },
 93→  });
 94→}
 95→
 96→function jsonResponse(data: unknown, status = 200): Response {
 97→  return new Response(JSON.stringify(data), {
 98→    status,
 99→    headers: { "content-type": "application/json" },
100→  });
101→}
102→
103→function redirect(location: string, status = 303): Response {
104→  return new Response(null, { status, headers: { location } });
105→}
106→
107→// ──────────────────────────────────────────────────────────────────
108→// Router
109→// ──────────────────────────────────────────────────────────────────
110→
111→export default {
112→  async fetch(request: Request, env: Env): Promise<Response> {
113→    try {
114→      const auth = await getAuthenticatedUserOrDev(request, env);
115→      const url = new URL(request.url);
116→      const path = url.pathname;
117→      const tz = (request.cf as Record<string, unknown> | undefined)?.timezone as string | undefined;
118→      const method = request.method;
119→
120→      // ── GET /programs/default.json ─────────────────────────────
121→      if (method === "GET" && path === "/programs/default.json") {
122→        return new Response(JSON.stringify(defaultProgramJson, null, 2), {
123→          headers: {
124→            "content-type": "application/json",
125→            "content-disposition": 'attachment; filename="default-program.json"',
126→          },
127→        });
128→      }
129→
130→      // ── GET / ──────────────────────────────────────────────────
131→      if (method === "GET" && path === "/") {
132→        const user = await getUser(env.DB, auth.userId);
133→        if (!user) {
134→          return htmlResponse(
135→            htmlShell({
136→              title: APP_NAME,
137→              subtitle: "Setup",
138→              body: `<div id="content">${setupPage()}</div>`,
139→            })
140→          );
141→        }
142→
143→        if (isSSERequest(request)) {
144→          return await handleTodaySSE(env, auth.userId, tz);
145→        }
146→
147→        const subtitle = await loadSubtitle(env.DB, auth.userId);
148→        return htmlResponse(
149→          htmlShell({
150→            title: APP_NAME,
151→            subtitle,
152→            activeTab: "today",
153→            ssePath: "/",
154→          })
155→        );
156→      }
157→
158→      // ── GET /progress ──────────────────────────────────────────
159→      if (method === "GET" && path === "/progress") {
160→        if (isSSERequest(request)) {
161→          return await handleProgressSSE(env, auth.userId);
162→        }
163→
164→        const subtitle = await loadSubtitle(env.DB, auth.userId);
165→        return htmlResponse(
166→          htmlShell({
167→            title: "Progress",
168→            subtitle,
169→            activeTab: "progress",
170→            ssePath: "/progress",
171→          })
172→        );
173→      }
174→
175→      // ── GET /program ──────────────────────────────────────────
176→      if (method === "GET" && path === "/program") {
177→        if (isSSERequest(request)) {
178→          return await handleProgramSSE(env, auth.userId);
179→        }
180→
181→        const subtitle = await loadSubtitle(env.DB, auth.userId);
182→        return htmlResponse(
183→          htmlShell({
184→            title: "Program",
185→            subtitle,
186→            activeTab: "program",
187→            ssePath: "/program",
188→          })
189→        );
190→      }
191→
192→      // ── GET /routine/:id ──────────────────────────────────────
193→      const routineMatch = path.match(/^\/routine\/([^/]+)$/);
194→      if (method === "GET" && routineMatch) {
195→        const routineId = decodeURIComponent(routineMatch[1]);
196→
197→        if (isSSERequest(request)) {
198→          return await handleRoutineSSE(env, auth.userId, routineId);
199→        }
200→
201→        return htmlResponse(
202→          htmlShell({
203→            title: "Routine",
204→            activeTab: "today",
205→            ssePath: `/routine/${encodeURIComponent(routineId)}`,
206→          })
207→        );
208→      }
209→
210→      // ── POST /api/validate-program ─────────────────────────────
211→      if (method === "POST" && path === "/api/validate-program") {
212→        return await handleValidateProgram(request);
213→      }
214→
215→      // ── POST /api/setup/:templateId ─────────────────────────────
216→      const setupMatch = path.match(/^\/api\/setup\/([^/]+)$/);
217→      if (method === "POST" && (path === "/api/setup" || setupMatch)) {
218→        const urlTemplateId = setupMatch ? decodeURIComponent(setupMatch[1]) : undefined;
219→        return await handleSetup(request, env, auth.userId, urlTemplateId, tz);
220→      }
221→
222→      // ── POST /api/push-hevy/:id ────────────────────────────────
223→      const pushMatch = path.match(/^\/api\/push-hevy\/([^/]+)$/);
224→      if (method === "POST" && pushMatch) {
225→        const routineId = decodeURIComponent(pushMatch[1]);
226→        return await handlePush(env, auth.userId, routineId);
227→      }
228→
229→      // ── POST /api/pull ─────────────────────────────────────────
230→      if (method === "POST" && path === "/api/pull") {
231→        return await handlePull(env, auth.userId, tz);
232→      }
233→
234→      // ── POST /api/cleanup-routines ───────────────────────────────
235→      if (method === "POST" && path === "/api/cleanup-routines") {
236→        return await handleCleanupRoutines(env, auth.userId);
237→      }
238→
239→      // ── POST /api/complete/:id ─────────────────────────────────
240→      const completeMatch = path.match(/^\/api\/complete\/([^/]+)$/);
241→      if (method === "POST" && completeMatch) {
242→        const itemId = parseInt(completeMatch[1], 10);
243→        return await handleManualComplete(env, auth.userId, itemId, tz);
244→      }
245→
246→      // ── 404 ────────────────────────────────────────────────────
247→      return new Response("Not Found", { status: 404 });
248→    } catch (err) {
249→      if (err instanceof Response) return err;
250→      const message = err instanceof Error ? err.message : "Internal Server Error";
251→      const stack = err instanceof Error ? err.stack : "";
252→      console.error("Unhandled error:", message, stack);
253→      return new Response(message, { status: 500 });
254→    }
255→  },
256→};
