379→/** SSE: Progress page — skills, roadmap, benchmarks */
380→async function handleProgressSSE(env: Env, userId: string): Promise<Response> {
381→  const program = await loadProgram(env.DB, userId);
382→  const fragments: string[] = [];
383→  let isFirst = true;
384→
385→  const addFragment = (html: string) => {
386→    fragments.push(patchElements(html, { selector: "#content", mode: isFirst ? "inner" : "append" }));
387→    isFirst = false;
388→  };
389→
390→  if (program.skills && program.skills.length > 0) {
391→    addFragment(skillCards(program.skills));
392→  }
393→
394→  if (program.roadmap && program.roadmap.length > 0) {
395→    addFragment(roadmapSection(program.roadmap));
396→  }
397→
398→  if (program.benchmarks && program.benchmarks.length > 0) {
399→    addFragment(benchmarksSection(program.benchmarks));
400→  }
401→
402→  return sseResponse(mergeFragments(fragments));
403→}
