405→/** SSE: Program page — overview, progressions, routines, foundations, resources, BODi */
406→async function handleProgramSSE(env: Env, userId: string): Promise<Response> {
407→  let program: Program;
408→  let user: Awaited<ReturnType<typeof getUser>>;
409→  try {
410→    [program, user] = await Promise.all([
411→      loadProgram(env.DB, userId),
412→      getUser(env.DB, userId),
413→    ]);
414→  } catch {
415→    return sseResponse(
416→      patchElements(`<div class="card"><p style="color:var(--text-secondary)">No active program. Upload a program to get started.</p></div>`, {
417→        selector: "#content", mode: "inner",
418→      })
419→    );
420→  }
421→  const fragments: string[] = [];
422→  let isFirst = true;
423→
424→  const addFragment = (html: string) => {
425→    fragments.push(patchElements(html, { selector: "#content", mode: isFirst ? "inner" : "append" }));
426→    isFirst = false;
427→  };
428→
429→  const week = user ? currentWeek(user.start_date) : null;
430→
431→  addFragment(programOverview(program, user, week));
432→
433→  if (program.progressions.length > 0) {
434→    addFragment(progressionsSection(program.progressions, week));
435→  }
436→
437→  addFragment(routinesSection(program));
438→
439→  if (program.foundations && program.foundations.length > 0) {
440→    addFragment(foundationsSection(program.foundations));
441→  }
442→
443→  if (program.resources && program.resources.length > 0) {
444→    addFragment(resourcesSection(program.resources));
445→  }
446→
447→  if (program.bodi && program.bodi.length > 0) {
448→    addFragment(bodiSection(program.bodi));
449→  }
450→
451→  return sseResponse(mergeFragments(fragments));
452→}
