454→/** SSE: Routine detail — exercise list with coaching context */
455→async function handleRoutineSSE(env: Env, userId: string, routineId: string): Promise<Response> {
456→  const program = await loadProgram(env.DB, userId);
457→  const routine = program.routines.find((r) => r.id === routineId);
458→  if (!routine) {
459→    return sseResponse(
460→      patchElements(`<p>Routine not found.</p>`, { selector: "#content", mode: "inner" })
461→    );
462→  }
463→
464→  // Look up user to determine current progression from start_date
465→  const user = await getUser(env.DB, userId);
466→  const week = user ? currentWeek(user.start_date) : null;
467→  const currentProgression = week != null
468→    ? findActiveProgression(week, program.progressions)
469→    : program.progressions[0];
470→
471→  const html = routineDetailPage(routine, program.exerciseTemplates, currentProgression);
472→  return sseResponse(
473→    patchElements(html, { selector: "#content", mode: "inner" })
474→  );
475→}
