477→/** POST /api/setup — store program, sync Hevy, create user, generate queue */
478→async function handleSetup(request: Request, env: Env, userId: string, urlTemplateId?: string, tz?: string): Promise<Response> {
479→  let body: { apiKey?: string; startDate?: string; templateId?: string; programJson?: string } = {};
480→  try {
481→    body = (await request.json()) as typeof body;
482→  } catch {
483→    // Body may be empty — that's OK, template ID comes from URL
484→  }
485→
486→  const templateId = urlTemplateId ?? body.templateId;
487→  const startDate = body.startDate || todayString(tz);
488→  const apiKey = body.apiKey || undefined;
489→  // Fall back to bundled default program if none uploaded
490→  const programJsonStr = body.programJson || JSON.stringify(defaultProgramJson);
491→
492→  if (!templateId) {
493→    return new Response("Template ID is required", { status: 400 });
494→  }
495→
496→  // Parse and validate program
497→  let program: Program;
498→  try {
499→    const parsed = JSON.parse(programJsonStr);
500→    const result = validateProgram(parsed);
501→    if (!result.valid) {
502→      return new Response(`Invalid program: ${result.errors.join(", ")}`, { status: 400 });
503→    }
504→    program = result.program;
505→  } catch {
506→    return new Response("Invalid program JSON", { status: 400 });
507→  }
508→
509→  const template = program.weekTemplates.find((t) => t.id === templateId);
510→  if (!template) {
511→    return new Response("Invalid template ID", { status: 400 });
512→  }
513→
514→  // Validate API key against Hevy before proceeding
515→  if (apiKey) {
516→    try {
517→      const client = new HevyClient(apiKey);
518→      await client.getExerciseTemplates(1, 1);
519→    } catch {
520→      return sseResponse(
521→        patchElements(
522→          `<div class="card"><p style="color:var(--orange)">Invalid Hevy API key. Check your key in Hevy Settings &gt; Developer and try again.</p></div>`,
523→          { selector: "#content", mode: "prepend" }
524→        )
525→      );
526→    }
527→  }
528→
529→  // h. Upsert user (must exist before program insert due to FK constraint)
530→  await upsertUser(env.DB, {
531→    id: userId,
532→    active_program: program.meta.title,
533→    template_id: templateId,
534→    start_date: startDate,
535→    hevy_api_key: apiKey,
536→  });
537→
538→  // a. Store program in D1
539→  await insertProgram(env.DB, userId, programJsonStr);
540→
541→  // b-g. Hevy exercise template & routine creation (only with API key)
542→  const routineIdMap = new Map<string, string>();
543→  if (apiKey) {
544→    const client = new HevyClient(apiKey);
545→
546→    // b. Fetch all Hevy exercise templates
547→    const hevyTemplates = await client.getAllExerciseTemplates();
548→
549→    // c. Auto-match our templates to Hevy's by normalized title
550→    const matched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
551→
552→    // d. Create custom Hevy exercise templates for unmatched
553→    const customCreated = new Set<string>();
554→    for (const et of program.exerciseTemplates) {
555→      if (!matched.has(et.id)) {
556→        const enums = mapToHevyEnums(et);
557→        const created = await client.createExerciseTemplate({
558→          title: et.title,
559→          exercise_type: enums.exerciseType,
560→          equipment_category: enums.equipmentCategory,
561→          muscle_group: enums.primaryMuscleGroup,
562→          other_muscles: enums.secondaryMuscleGroups,
563→        });
564→        matched.set(et.id, created.id);
565→        customCreated.add(et.id);
566→      }
567→    }
568→
569→    // e. Save all exercise template mappings
570→    for (const [programTemplateId, hevyTemplateId] of matched) {
571→      await upsertExerciseTemplateMapping(env.DB, {
572→        user_id: userId,
573→        program_template_id: programTemplateId,
574→        hevy_template_id: hevyTemplateId,
575→        is_custom: customCreated.has(programTemplateId) ? 1 : 0,
576→      });
577→    }
578→
579→    // f. Create or update Hevy routines with folder grouping + dedup
580→    const allMappings = await getExerciseTemplateMappings(env.DB, userId);
581→    const existingRoutineMappings = await getRoutineMappings(env.DB, userId);
582→    const existingMappingsMap = new Map(
583→      existingRoutineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
584→    );
585→
586→    // Compute folder assignments and create/find folders
587→    const folderAssignments = computeFolderAssignments(program.routines, program.meta.title);
588→    const uniqueFolderNames = [...new Set(folderAssignments.map((a) => a.folderName))];
589→    const folderNameToId = new Map<string, number>();
590→    for (const name of uniqueFolderNames) {
591→      const folder = await client.getOrCreateRoutineFolder(name);
592→      folderNameToId.set(name, folder.id);
593→    }
594→
595→    // Fetch existing Hevy routines for dedup by title+folder
596→    const existingHevyRoutines = await client.getAllRoutines();
597→
598→    // Reconcile: decide create vs update for each routine
599→    const reconciliations = reconcileRoutines(
600→      folderAssignments, existingHevyRoutines, folderNameToId, existingMappingsMap
601→    );
602→
603→    for (const recon of reconciliations) {
604→      const routine = program.routines.find((r) => r.id === recon.programRoutineId)!;
605→      const payload = buildRoutinePayload(routine, allMappings);
606→      const folderId = folderNameToId.get(recon.folderName)!;
607→
608→      if (recon.action === "update" && recon.existingHevyRoutineId) {
609→        await client.updateRoutine(recon.existingHevyRoutineId, {
610→          title: payload.title,
611→          exercises: payload.exercises,
612→        });
613→        routineIdMap.set(routine.id, recon.existingHevyRoutineId);
614→      } else {
615→        const created = await client.createRoutine({
616→          title: payload.title,
617→          folder_id: folderId,
618→          exercises: payload.exercises,
619→        });
620→        routineIdMap.set(routine.id, created.id);
621→      }
622→    }
623→
624→    // g. Save all routine mappings
625→    for (const [programRoutineId, hevyRoutineId] of routineIdMap) {
626→      await upsertRoutineMapping(env.DB, {
627→        user_id: userId,
628→        program_routine_id: programRoutineId,
629→        hevy_routine_id: hevyRoutineId,
630→      });
631→    }
632→  }
633→
634→  // i. Generate queue playlist
635→  const weeks = program.meta.durationWeeks || 8;
636→  const playlist = generatePlaylist(template, program.routines, weeks);
637→  if (playlist.length > 0) {
638→    await insertQueueItems(env.DB, userId, playlist);
639→  }
640→
641→  // j. Bulk-set hevy_routine_id on queue items via routine_mappings
642→  if (apiKey) {
643→    await bulkSetQueueItemRoutineIds(env.DB, userId, routineIdMap);
644→  }
645→
646→  // k. Redirect to Today
647→  return sseResponse(executeScript("window.location.href = '/'"));
648→}
