650→/** POST /api/push-hevy/:id — open routine in Hevy (uses existing mapping from setup) */
651→async function handlePush(env: Env, userId: string, routineId: string): Promise<Response> {
652→  const user = await getUser(env.DB, userId);
653→  if (!user || !user.hevy_api_key) {
654→    return sseResponse(
655→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
656→        selector: "#content",
657→        mode: "inner",
658→      })
659→    );
660→  }
661→
662→  // Look up existing routine mapping from setup
663→  const routineMappings = await getRoutineMappings(env.DB, userId);
664→  const mapping = routineMappings.find((m) => m.program_routine_id === routineId);
665→
666→  if (mapping) {
667→    // Routine already exists in Hevy — open it directly
668→    return sseResponse(
669→      executeScript(`window.open('https://hevy.com/routine/${mapping.hevy_routine_id}', '_blank')`)
670→    );
671→  }
672→
673→  // Fallback: no mapping exists (edge case — setup didn't create this routine)
674→  const program = await loadProgram(env.DB, userId);
675→  const routine = program.routines.find((r) => r.id === routineId);
676→  if (!routine) {
677→    return new Response("Routine not found", { status: 404 });
678→  }
679→
680→  const client = new HevyClient(user.hevy_api_key);
681→
682→  // Get or auto-create exercise template mappings
683→  let mappings = await getExerciseTemplateMappings(env.DB, userId);
684→  if (mappings.length === 0) {
685→    try {
686→      const hevyTemplates = await client.getAllExerciseTemplates();
687→      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
688→
689→      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
690→        await upsertExerciseTemplateMapping(env.DB, {
691→          user_id: userId,
692→          program_template_id: programTemplateId,
693→          hevy_template_id: hevyTemplateId,
694→          is_custom: 0,
695→        });
696→      }
697→      mappings = await getExerciseTemplateMappings(env.DB, userId);
698→    } catch {
699→      // If auto-match fails, continue with empty mappings
700→    }
701→  }
702→
703→  const payload = buildRoutinePayload(routine, mappings);
704→
705→  if (payload.exercises.length === 0) {
706→    return sseResponse(
707→      patchElements(
708→        `<div class="card"><p style="color:var(--orange)">Cannot push: no exercises could be mapped to Hevy templates. ${payload.unmapped.length} unmapped exercise(s).</p></div>`,
709→        { selector: "#content", mode: "prepend" }
710→      )
711→    );
712→  }
713→
714→  try {
715→    const folder = await client.getOrCreateRoutineFolder(program.meta.title);
716→    const created = await client.createRoutine({
717→      title: payload.title,
718→      folder_id: folder.id,
719→      exercises: payload.exercises,
720→    });
721→
722→    // Save the mapping so future pushes use the existing routine
723→    await upsertRoutineMapping(env.DB, {
724→      user_id: userId,
725→      program_routine_id: routineId,
726→      hevy_routine_id: created.id,
727→    });
728→
729→    // Also update the queue item if there is one
730→    const items = await getQueueItems(env.DB, userId);
731→    const queueItem = items.find(
732→      (i) => i.routine_id === routineId && i.status === "pending"
733→    );
734→    if (queueItem) {
735→      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, created.id);
736→    }
737→
738→    return sseResponse(
739→      executeScript(`window.open('https://hevy.com/routine/${created.id}', '_blank')`)
740→    );
741→  } catch (err) {
742→    const msg = escapeHtml(err instanceof Error ? err.message : "Push failed");
743→    return sseResponse(
744→      patchElements(
745→        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
746→        { selector: "#content", mode: "prepend" }
747→      )
748→    );
749→  }
750→}
