808→/** POST /api/pull — pull completions from Hevy */
809→async function handlePull(env: Env, userId: string, tz?: string): Promise<Response> {
810→  const user = await getUser(env.DB, userId);
811→  if (!user || !user.hevy_api_key) {
812→    return sseResponse(
813→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
814→        selector: "#content",
815→        mode: "inner",
816→      })
817→    );
818→  }
819→
820→  const program = await loadProgram(env.DB, userId);
821→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
822→  const client = new HevyClient(user.hevy_api_key);
823→
824→  try {
825→    const [workouts, items] = await Promise.all([
826→      client.getRecentWorkouts(),
827→      getQueueItems(env.DB, userId),
828→    ]);
829→
830→    // Skip workouts already matched to a completed queue item
831→    const usedWorkoutIds = new Set(
832→      items.filter((i) => i.hevy_workout_id).map((i) => i.hevy_workout_id)
833→    );
834→    const newWorkouts = workouts.filter((w) => !usedWorkoutIds.has(w.id));
835→
836→    const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);
837→
838→    const nameToRoutineId = new Map<string, string>();
839→    for (const item of pendingItems) {
840→      const routine = routineMap.get(item.routine_id);
841→      if (routine && item.hevy_routine_id) {
842→        nameToRoutineId.set(routine.title, item.hevy_routine_id);
843→      }
844→    }
845→
846→    const matches = matchCompletions(
847→      pendingItems,
848→      newWorkouts,
849→      (w) => nameToRoutineId.get(w.title) ?? null
850→    );
851→
852→    // Build workout ID → local date map for accurate completion dates
853→    const workoutDateMap = new Map<string, string>();
854→    for (const w of newWorkouts) {
855→      const d = tz
856→        ? new Date(w.start_time).toLocaleDateString("en-CA", { timeZone: tz })
857→        : w.start_time.slice(0, 10);
858→      workoutDateMap.set(w.id, d);
859→    }
860→
861→    for (const match of matches) {
862→      const completedDate = workoutDateMap.get(match.workoutId) ?? todayString(tz);
863→      await markQueueItemCompleted(env.DB, match.queueItemId, completedDate, match.workoutId);
864→    }
865→
866→    // Check for daily routine completion (use workout date, not sync date)
867→    const dailyRoutine = program.routines.find((r) => r.isDaily);
868→    if (dailyRoutine) {
869→      const dailyWorkout = workouts.find((w) => w.title === dailyRoutine.title);
870→      if (dailyWorkout) {
871→        const workoutDate = tz
872→          ? new Date(dailyWorkout.start_time).toLocaleDateString("en-CA", { timeZone: tz })
873→          : dailyWorkout.start_time.slice(0, 10);
874→        await updateDailyCompleted(env.DB, userId, workoutDate);
875→      }
876→    }
877→
878→    // Re-render today page
879→    return await handleTodaySSE(env, userId, tz);
880→  } catch (err) {
881→    const msg = escapeHtml(err instanceof Error ? err.message : "Pull failed");
882→    return sseResponse(
883→      patchElements(
884→        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
885→        { selector: "#content", mode: "prepend" }
886→      )
887→    );
888→  }
889→}
