891→/** POST /api/complete/:id — manual complete, re-render today */
892→async function handleManualComplete(
893→  env: Env,
894→  userId: string,
895→  itemId: number,
896→  tz?: string
897→): Promise<Response> {
898→  if (!Number.isInteger(itemId)) {
899→    return new Response("Invalid item ID", { status: 400 });
900→  }
901→  const today = todayString(tz);
902→  await markQueueItemCompletedForUser(env.DB, itemId, userId, today);
903→  return await handleTodaySSE(env, userId, tz);
904→}
