  1→import type { Routine, ExerciseTemplate, ExerciseTemplateMappingRow, QueueItemRow } from "../types";
  2→import type { HevyRoutineExercise, HevySet, HevyWorkout, HevyExerciseTemplate } from "../hevy/client";
  3→
  4→// ──────────────────────────────────────────────────────────────────
  5→// Sets string parser
  6→// ──────────────────────────────────────────────────────────────────
  7→
  8→/**
  9→ * Parse a sets string like "3×8", "3×30 sec", "2×45 sec", "3×1 min"
 10→ * into an array of HevySet objects.
 11→ *
 12→ * - Patterns containing "sec" or "min" produce duration_seconds sets.
 13→ * - All other patterns produce reps sets.
 14→ */
 15→function parseSetsString(setsStr: string): HevySet[] {
 16→  // Normalise the multiplication sign — programs may use × (U+00D7) or x
 17→  const normalised = setsStr.replace(/×/g, "x");
 18→
 19→  // Match "NxM sec", "NxM min", or "NxM"
 20→  const match = normalised.match(/^(\d+)\s*x\s*(\d+(?:\.\d+)?)\s*(sec|min)?/i);
 21→  if (!match) {
 22→    // Fallback: return a single normal set with no values
 23→    return [{ type: "normal", reps: null }];
 24→  }
 25→
 26→  const count = parseInt(match[1], 10);
 27→  const value = parseFloat(match[2]);
 28→  const unit = match[3]?.toLowerCase();
 29→
 30→  const isDuration = unit === "sec" || unit === "min";
 31→  const duration_seconds = isDuration
 32→    ? unit === "min"
 33→      ? Math.round(value * 60)
 34→      : Math.round(value)
 35→    : undefined;
 36→
 37→  const sets: HevySet[] = [];
 38→  for (let i = 0; i < count; i++) {
 39→    if (isDuration) {
 40→      sets.push({ type: "normal", reps: null, duration_seconds });
 41→    } else {
 42→      const reps = Math.round(value);
 43→      sets.push({ type: "normal", reps });
 44→    }
 45→  }
 46→  return sets;
 47→}
