 65→export function buildRoutinePayload(
 66→  routine: Routine,
 67→  mappings: ExerciseTemplateMappingRow[]
 68→): RoutinePayload {
 69→  const mappingMap = new Map(
 70→    mappings.map((m) => [m.program_template_id, m.hevy_template_id])
 71→  );
 72→
 73→  const exercises: HevyRoutineExercise[] = [];
 74→  const unmapped: string[] = [];
 75→
 76→  for (const exercise of routine.exercises) {
 77→    const hevyId = mappingMap.get(exercise.exerciseTemplateId);
 78→    if (!hevyId) {
 79→      unmapped.push(exercise.exerciseTemplateId);
 80→      continue;
 81→    }
 82→
 83→    const sets = parseSetsString(exercise.sets);
 84→
 85→    exercises.push({
 86→      exercise_template_id: hevyId,
 87→      sets,
 88→      notes: exercise.notes,
 89→    });
 90→  }
 91→
 92→  return { title: routine.title, exercises, unmapped };
 93→}
