 8→/**
 9→ * Full routine detail page content — exercise list with numbered items,
10→ * sets in blue, coaching notes, video links, integration tags,
11→ * and a sticky Push to Hevy button.
12→ */
13→export function routineDetailPage(
14→  routine: Routine,
15→  exerciseTemplates: ExerciseTemplate[],
16→  currentProgression?: Progression
17→): string {
18→  const parts: string[] = [];
19→
20→  const templateMap = new Map(exerciseTemplates.map((t) => [t.id, t]));
21→
22→  // Back nav
23→  parts.push(`<a href="/" class="back-nav">&#8249; Today</a>`);
24→
25→  // Routine header
26→  parts.push(`<div style="margin-bottom:16px">
27→  <h2 class="card-title" style="font-size:22px">${escapeHtml(routine.title)}</h2>
28→  ${routine.subtitle ? `<p class="card-subtitle">${escapeHtml(routine.subtitle)}</p>` : ""}
29→  ${routine.description ? `<p class="card-desc">${escapeHtml(routine.description)}</p>` : ""}
30→</div>`);
31→
32→  // Phase coaching callout (no border-left accent)
33→  if (currentProgression) {
34→    const detailsHtml = currentProgression.details?.length
35→      ? `<ul class="coaching-details">${currentProgression.details.map((d) => `<li>${escapeHtml(d)}</li>`).join("")}</ul>`
36→      : "";
37→
38→    parts.push(`<div class="coaching-callout">
39→  <div class="coaching-label">${escapeHtml(currentProgression.phaseName)} Phase &middot; ${escapeHtml(currentProgression.weekRange)}</div>
40→  ${currentProgression.focus ? `<div class="coaching-focus">${escapeHtml(currentProgression.focus)}</div>` : ""}
41→  ${detailsHtml}
42→</div>`);
43→  }
44→
45→  // Exercise list
46→  parts.push(`<div class="section-header">Exercises (${routine.exercises.length})</div>`);
47→
48→  routine.exercises.forEach((routineExercise, index) => {
49→    const template = templateMap.get(routineExercise.exerciseTemplateId);
50→
51→    // Title always comes from the template; fall back to ID if template missing
52→    const title = template?.title ?? routineExercise.exerciseTemplateId;
53→
54→    const setsDisplay = routineExercise.sets;
55→    const notes = routineExercise.notes ?? template?.notes;
56→
57→    const videoLink = template?.videoURL
58→      ? `<a href="${escapeAttr(template.videoURL)}" target="_blank" rel="noopener" class="exercise-video">&#9654; Watch tutorial</a>`
59→      : "";
60→
61→    const tagsHtml =
62→      template?.tags && template.tags.length > 0
63→        ? `<div class="exercise-tags">${template.tags.map((t) => `<span class="exercise-tag">${escapeHtml(formatTag(t))}</span>`).join("")}</div>`
64→        : "";
65→
66→    const notesHtml = notes
67→      ? `<div class="exercise-notes">${escapeHtml(notes)}</div>`
68→      : "";
69→
70→    parts.push(`<div class="exercise-item">
71→  <div class="exercise-header">
72→    <span class="exercise-number">${index + 1}</span>
73→    <span class="exercise-name">${escapeHtml(title)}</span>
74→    ${setsDisplay ? `<span class="exercise-sets">${escapeHtml(setsDisplay)}</span>` : ""}
75→  </div>
76→  ${notesHtml}
77→  ${videoLink}
78→  ${tagsHtml}
79→</div>`);
80→  });
81→
82→  // Sticky Push to Hevy
83→  parts.push(`<div class="sticky-footer">
84→  <button class="btn btn-blue btn-block" data-on:click="@post('/api/push-hevy/${escapeAttr(routine.id)}')">Push to Hevy</button>
85→</div>`);
86→
87→  return parts.join("\n");
88→}
