90→/** Convert a tag like "core-integration" to "Core Integration" */
91→function formatTag(tag: string): string {
92→  return tag
93→    .split("-")
94→    .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
95→    .join(" ");
96→}
