153→export async function insertProgram(
154→  db: D1Database,
155→  userId: string,
156→  jsonData: string
157→): Promise<number> {
158→  const deactivate = db
159→    .prepare("UPDATE programs SET is_active = 0 WHERE user_id = ? AND is_active = 1")
160→    .bind(userId);
161→  const insert = db
162→    .prepare("INSERT INTO programs (user_id, json_data) VALUES (?, ?)")
163→    .bind(userId, jsonData);
164→  const [, insertResult] = await db.batch([deactivate, insert]);
165→  const id = insertResult.meta.last_row_id;
166→  if (id == null) throw new Error(`Failed to insert program for user ${userId}`);
167→  return id;
168→}
