262→/** POST /api/validate-program — validate uploaded JSON, return template cards */
263→async function handleValidateProgram(request: Request): Promise<Response> {
264→  const body = (await request.json()) as Record<string, unknown>;
265→  // Fall back to bundled default program if none uploaded
266→  const programJsonStr = (body.programJson as string | undefined) || JSON.stringify(defaultProgramJson);
267→
268→  let parsed: unknown;
269→  try {
270→    parsed = JSON.parse(programJsonStr);
271→  } catch {
272→    return sseResponse(
273→      patchElements(
274→        `<div class="card"><p style="color:var(--orange)">Invalid JSON file.</p></div>`,
275→        { selector: "#validation-result", mode: "inner" }
276→      )
277→    );
278→  }
279→
280→  const result = validateProgram(parsed);
281→  if (!result.valid) {
282→    const errorList = result.errors
283→      .map((e) => `<li>${escapeHtml(e)}</li>`)
284→      .join("");
285→    return sseResponse(
286→      patchElements(
287→        `<div class="card"><p style="color:var(--orange)">Validation errors:</p><ul style="margin:8px 0 0 16px;font-size:13px;color:var(--text-secondary)">${errorList}</ul></div>`,
288→        { selector: "#validation-result", mode: "inner" }
289→      )
290→    );
291→  }
292→
293→  return sseResponse(
294→    patchElements(templateSelectionFragment(result.program.weekTemplates), {
295→      selector: "#validation-result",
296→      mode: "inner",
297→    })
298→  );
299→}
