301→/** SSE: Today page — CARs card, hero session, completed, upcoming */
302→async function handleTodaySSE(env: Env, userId: string, tz?: string): Promise<Response> {
303→  const user = await getUser(env.DB, userId);
304→  if (!user) {
305→    return sseResponse(
306→      patchElements(setupPage(), { selector: "#content", mode: "inner" })
307→    );
308→  }
309→
310→  const program = await loadProgram(env.DB, userId);
311→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
312→  const dailyRoutine = program.routines.find((r) => r.isDaily);
313→
314→  const items = await getQueueItems(env.DB, userId);
315→  const today = todayString(tz);
316→
317→  // Look up routine mappings for deep links
318→  const routineMappings = await getRoutineMappings(env.DB, userId);
319→  const routineToHevyId = new Map(
320→    routineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
321→  );
322→
323→  const fragments: string[] = [];
324→
325→  const dailyDoneToday = dailyRoutine && user.daily_completed_date === today;
326→
327→  if (dailyRoutine && !dailyDoneToday) {
328→    fragments.push(patchElements(carsCard(dailyRoutine, routineToHevyId.get(dailyRoutine.id)), { selector: "#content", mode: "inner" }));
329→  }
330→
331→  // Hero session card — next pending
332→  const nextItem = getNextRoutine(items);
333→  if (nextItem) {
334→    const routine = routineMap.get(nextItem.routine_id);
335→    if (routine) {
336→      const mode = (dailyRoutine && !dailyDoneToday) ? "append" : "inner";
337→      fragments.push(
338→        patchElements(heroRoutineCard(routine, nextItem), { selector: "#content", mode })
339→      );
340→    }
341→  }
342→
343→  // Completed today
344→  const completed = getCompletedRoutines(items, today);
345→  const completedData = completed.map((item) => ({
346→    title: routineMap.get(item.routine_id)?.title ?? item.routine_id,
347→  }));
348→  if (dailyDoneToday) {
349→    completedData.unshift({ title: dailyRoutine.title });
350→  }
351→  if (completedData.length > 0) {
352→    fragments.push(
353→      patchElements(completedSection(completedData), { selector: "#content", mode: "append" })
354→    );
355→  }
356→
357→  // Upcoming (next 5 sessions)
358→  const template = program.weekTemplates.find((t) => t.id === user.template_id);
359→  if (template) {
360→    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
361→    // Skip the first pending (already shown as hero) for upcoming
362→    const upcomingPending = pendingItems.slice(1);
363→    const upcoming = computeUpcoming(upcomingPending, template, program.routines, 5);
364→    if (upcoming.length > 0) {
365→      fragments.push(
366→        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
367→      );
368→    }
369→  }
370→
371→  // Sync button at the bottom
372→  fragments.push(
373→    patchElements(syncButton(), { selector: "#content", mode: "append" })
374→  );
375→
376→  return sseResponse(mergeFragments(fragments));
377→}
