752→/** POST /api/cleanup-routines — delete duplicate routines from Hevy */
753→async function handleCleanupRoutines(env: Env, userId: string): Promise<Response> {
754→  const user = await getUser(env.DB, userId);
755→  if (!user || !user.hevy_api_key) {
756→    return sseResponse(
757→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
758→        selector: "#content",
759→        mode: "prepend",
760→      })
761→    );
762→  }
763→
764→  const client = new HevyClient(user.hevy_api_key);
765→  const allRoutines = await client.getAllRoutines();
766→
767→  // Group by title+folder, find duplicates
768→  const byKey = new Map<string, typeof allRoutines>();
769→  for (const r of allRoutines) {
770→    const key = `${r.title}::${r.folder_id ?? "none"}`;
771→    const list = byKey.get(key) ?? [];
772→    list.push(r);
773→    byKey.set(key, list);
774→  }
775→
776→  const toDelete: string[] = [];
777→  for (const [, routines] of byKey) {
778→    if (routines.length > 1) {
779→      // Keep the most recently updated, delete the rest
780→      routines.sort((a, b) => (b.updated_at ?? "").localeCompare(a.updated_at ?? ""));
781→      toDelete.push(...routines.slice(1).map((r) => r.id));
782→    }
783→  }
784→
785→  let deleted = 0;
786→  let failed = 0;
787→  for (const id of toDelete) {
788→    try {
789→      await client.deleteRoutine(id);
790→      deleted++;
791→    } catch {
792→      failed++;
793→    }
794→  }
795→
796→  const msg = toDelete.length === 0
797→    ? "No duplicates found."
798→    : `Cleaned up ${deleted} duplicate(s)${failed > 0 ? `, ${failed} failed` : ""}.`;
799→
800→  return sseResponse(
801→    patchElements(
802→      `<div class="card"><p style="color:var(--green)">${escapeHtml(msg)}</p></div>`,
803→      { selector: "#content", mode: "prepend" }
804→    )
805→  );
806→}
