186→// ──────────────────────────────────────────────────────────────────
187→// matchCompletions
188→// ──────────────────────────────────────────────────────────────────
189→
190→export interface CompletionMatch {
191→  queueItemId: number;
192→  workoutId: string;
193→}
194→
195→/**
196→ * Match Hevy workouts to queue items by comparing each workout's routine ID
197→ * (obtained via `getRoutineId`) to the `hevy_routine_id` stored on the queue
198→ * item.
199→ *
200→ * Each workout is matched to at most one queue item.
201→ */
202→export function matchCompletions(
203→  items: Pick<QueueItemRow, "id" | "hevy_routine_id">[],
204→  workouts: HevyWorkout[],
205→  getRoutineId: (workout: HevyWorkout) => string | null
206→): CompletionMatch[] {
207→  // Build a map: routine_id → queue item id (first match wins)
208→  const routineToItem = new Map<string, number>();
209→  for (const item of items) {
210→    if (item.hevy_routine_id && !routineToItem.has(item.hevy_routine_id)) {
211→      routineToItem.set(item.hevy_routine_id, item.id);
212→    }
213→  }
214→
215→  const matches: CompletionMatch[] = [];
216→  const usedItems = new Set<number>();
217→
218→  for (const workout of workouts) {
219→    const routineId = getRoutineId(workout);
220→    if (!routineId) continue;
221→
222→    const itemId = routineToItem.get(routineId);
223→    if (itemId !== undefined && !usedItems.has(itemId)) {
224→      matches.push({ queueItemId: itemId, workoutId: workout.id });
225→      usedItems.add(itemId);
226→    }
227→  }
228→
229→  return matches;
230→}
231→
232→// ──────────────────────────────────────────────────────────────────
233→// autoMatchExercises
234→// ──────────────────────────────────────────────────────────────────
235→
236→/**
237→ * Normalize an exercise name for fuzzy matching:
238→ * - Lowercase
239→ * - Strip non-alphanumeric characters (spaces, hyphens, punctuation)
240→ * - Strip a trailing 's' (basic singular/plural normalisation)
241→ */
242→function normalizeName(name: string): string {
243→  return name
244→    .toLowerCase()
245→    .replace(/[^a-z0-9]/g, "")
246→    .replace(/s$/, "");
247→}
248→
249→/**
250→ * Attempt to automatically match our exercise templates to Hevy exercise
251→ * template IDs using normalized title comparison. Supports partial matching
252→ * (one normalized name contains the other).
253→ *
254→ * Returns a Map of our template ID → Hevy template ID for every template
255→ * that could be matched.
256→ */
257→export function autoMatchExercises(
258→  ourTemplates: ExerciseTemplate[],
259→  hevyTemplates: HevyExerciseTemplate[]
260→): Map<string, string> {
261→  const result = new Map<string, string>();
262→
263→  // Pre-normalize Hevy template titles
264→  const normalizedHevy = hevyTemplates.map((t) => ({
265→    id: t.id,
266→    norm: normalizeName(t.title),
267→  }));
268→
269→  for (const template of ourTemplates) {
270→    const normOurs = normalizeName(template.title);
271→
272→    // Prefer exact match first
273→    let matched = normalizedHevy.find((t) => t.norm === normOurs);
274→
275→    // Fall back to partial match (one contains the other)
276→    if (!matched) {
277→      matched = normalizedHevy.find(
278→        (t) => t.norm.includes(normOurs) || normOurs.includes(t.norm)
279→      );
280→    }
281→
282→    if (matched) {
283→      result.set(template.id, matched.id);
284→    }
285→  }
286→
287→  return result;
288→}
