 1→import type { WeekTemplate, Routine, QueueItemRow } from "../types";
 2→
 3→interface PlaylistItem {
 4→  routine_id: string;
 5→  position: number;
 6→}
 7→
 8→export function generatePlaylist(
 9→  template: WeekTemplate,
10→  routines: Routine[],
11→  weeks: number
12→): PlaylistItem[] {
13→  const routineMap = new Map(routines.map((r) => [r.id, r]));
14→  const mainRoutineOrder: string[] = [];
15→
16→  for (const day of template.days) {
17→    if (!day.routineIDs) continue;
18→    for (const rid of day.routineIDs) {
19→      const routine = routineMap.get(rid);
20→      if (routine && !routine.isDaily) {
21→        mainRoutineOrder.push(rid);
22→      }
23→    }
24→  }
25→
26→  const playlist: PlaylistItem[] = [];
27→  for (let week = 0; week < weeks; week++) {
28→    for (const rid of mainRoutineOrder) {
29→      playlist.push({
30→        routine_id: rid,
31→        position: playlist.length,
32→      });
33→    }
34→  }
35→
36→  return playlist;
37→}
38→
39→export function getNextRoutine(items: QueueItemRow[]): QueueItemRow | null {
40→  const sorted = [...items].sort((a, b) => a.position - b.position);
41→  return sorted.find((item) => item.status === "pending") ?? null;
42→}
43→
44→export function getCompletedRoutines(items: QueueItemRow[], today: string): QueueItemRow[] {
45→  return items
46→    .filter((item) => item.status === "completed" && item.completed_date === today)
47→    .sort((a, b) => a.position - b.position);
48→}
