 1→// @ts-expect-error — generated module has no type declarations
 2→import validate from "../domain/compiled-validator.mjs";
 3→import type { Program } from "../types";
 4→
 5→export type ValidationResult =
 6→  | { valid: true; program: Program }
 7→  | { valid: false; errors: string[] };
 8→
 9→export function validateProgram(data: unknown): ValidationResult {
10→  if (validate(data)) {
11→    return { valid: true, program: data as unknown as Program };
12→  }
13→
14→  const errors = (validate.errors ?? []).map(
15→    (e: { instancePath?: string; message?: string }) => {
16→      const path = e.instancePath || "/";
17→      return `${path}: ${e.message ?? "unknown error"}`;
18→    }
19→  );
20→
21→  return { valid: false, errors };
22→}
