  1→// ──────────────────────────────────────────────────────────────────
  2→// Program page fragments — overview, progressions, routines,
  3→// foundations, resources, BODi
  4→// ──────────────────────────────────────────────────────────────────
  5→
  6→import type { Program, Progression, Foundation, Resource, BodiIntegration, UserRow } from "../types";
  7→import { escapeHtml, escapeAttr } from "../utils/html";
  8→import { findActiveProgression } from "../domain/schedule";
  9→
 10→// ── Program overview card ──────────────────────────────────────────
 11→
 12→export function programOverview(program: Program, user: UserRow | null, week: number | null): string {
 13→  const template = user
 14→    ? program.weekTemplates.find((t) => t.id === user.template_id)
 15→    : undefined;
 16→
 17→  const phase = week != null ? findActiveProgression(week, program.progressions) : undefined;
 18→  const exerciseCount = program.exerciseTemplates.length;
 19→  const routineCount = program.routines.filter((r) => !r.isDaily).length;
 20→
 21→  // Stats row
 22→  const stats: string[] = [];
 23→  if (week != null) stats.push(`<div class="stat-item"><div class="stat-value">${week}</div><div class="stat-label">Week</div></div>`);
 24→  stats.push(`<div class="stat-item"><div class="stat-value">${routineCount}</div><div class="stat-label">Routines</div></div>`);
 25→  stats.push(`<div class="stat-item"><div class="stat-value">${exerciseCount}</div><div class="stat-label">Exercises</div></div>`);
 26→  if (template) {
 27→    const daysPerWeek = template.days.filter((d) => d.routineIDs && d.routineIDs.length > 0).length;
 28→    stats.push(`<div class="stat-item"><div class="stat-value">${daysPerWeek}</div><div class="stat-label">Days/Wk</div></div>`);
 29→  }
 30→
 31→  const statsRow = `<div style="display:flex;gap:4px;margin-top:12px">${stats.join("")}</div>`;
 32→
 33→  // Phase badge
 34→  const phaseBadge = phase
 35→    ? `<div style="display:inline-block;font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--green);background:rgba(48,209,88,0.1);padding:4px 10px;border-radius:6px;margin-top:10px">${escapeHtml(phase.phaseName)}${phase.weekRange ? ` \u00B7 ${escapeHtml(phase.weekRange)}` : ""}</div>`
 36→    : "";
 37→
 38→  return `<div class="card">
 39→  <div class="card-label" style="color:var(--blue)">Program</div>
 40→  <div class="card-title">${escapeHtml(program.meta.title)}</div>
 41→  ${program.meta.description ? `<div class="card-desc">${escapeHtml(program.meta.description)}</div>` : ""}
 42→  ${phaseBadge}
 43→  ${statsRow}
 44→</div>`;
 45→}
 46→
 47→// ── Progressions timeline ──────────────────────────────────────────
 48→
 49→export function progressionsSection(progressions: Progression[], currentWk: number | null): string {
 50→  if (progressions.length === 0) return "";
 51→
 52→  const sorted = [...progressions].sort((a, b) => (a.weekStart ?? 0) - (b.weekStart ?? 0));
 53→
 54→  const items = sorted.map((p) => {
 55→    const isCurrent = currentWk != null && p.weekStart != null && p.weekEnd != null
 56→      && currentWk >= p.weekStart && currentWk <= p.weekEnd;
 57→    const isPast = currentWk != null && p.weekEnd != null && currentWk > p.weekEnd;
 58→    const dotColor = isCurrent ? "var(--green)" : isPast ? "var(--blue)" : "var(--text-tertiary)";
 59→    const cls = isCurrent ? " roadmap-current" : "";
 60→
 61→    return `<div class="roadmap-item${cls}">
 62→  <div class="roadmap-indicator" style="background:${dotColor}"></div>
 63→  <div>
 64→    <div class="roadmap-name">${escapeHtml(p.phaseName)}</div>
