 94→
 95→    return `<a href="/routine/${encodeURIComponent(r.id)}" style="text-decoration:none;color:inherit;display:block">
 96→  <div style="padding:12px 0;display:flex;align-items:center;gap:12px">
 97→    <div style="width:4px;height:36px;border-radius:2px;background:${color};flex-shrink:0"></div>
 98→    <div style="flex:1;min-width:0">
 99→      <div style="font-size:15px;font-weight:600">${escapeHtml(r.title)}</div>
100→      <div style="font-size:12px;color:var(--text-tertiary);margin-top:2px">${exCount} exercise${exCount !== 1 ? "s" : ""}${muscles ? ` \u00B7 ${escapeHtml(muscles)}` : ""}</div>
101→    </div>
102→    <svg style="width:16px;height:16px;color:var(--text-tertiary);flex-shrink:0" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="9 18 15 12 9 6"/></svg>
103→  </div>
104→</a>`;
105→  }
106→
107→  const dailyHtml = daily.length > 0
108→    ? daily.map((r) => routineCard(r)).join(`<div style="border-top:1px solid var(--separator)"></div>`)
109→    : "";
