111→  const sessionsHtml = sessions
112→    .sort((a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0))
113→    .map((r) => routineCard(r))
114→    .join(`<div style="border-top:1px solid var(--separator)"></div>`);
