 1→export interface PatchOptions {
 2→  selector?: string;
 3→  mode?: "outer" | "inner" | "append" | "prepend" | "before" | "after" | "remove";
 4→  useViewTransition?: boolean;
 5→}
 6→
 7→export function patchElements(html: string, opts?: PatchOptions): string {
 8→  let lines = `event: datastar-patch-elements\n`;
 9→  if (opts?.selector) lines += `data: selector ${opts.selector}\n`;
10→  if (opts?.mode) lines += `data: mode ${opts.mode}\n`;
11→  if (opts?.useViewTransition) lines += `data: useViewTransition true\n`;
12→  // Datastar v1: each continuation line must repeat "data: elements "
13→  const htmlLines = html.replace(/\n/g, "\ndata: elements ");
14→  lines += `data: elements ${htmlLines}\n\n`;
15→  return lines;
16→}
17→
18→export function patchSignals(signals: Record<string, unknown>): string {
19→  return `event: datastar-patch-signals\ndata: signals ${JSON.stringify(signals)}\n\n`;
20→}
21→
22→export function mergeFragments(fragments: string[]): string {
23→  return fragments.join("");
24→}
25→
26→export function sseResponse(body: string): Response {
27→  return new Response(body, {
28→    headers: {
29→      "content-type": "text/event-stream",
30→      "cache-control": "private, no-store",
31→      "vary": "Accept",
32→    },
33→  });
34→}
35→
36→export function executeScript(script: string): string {
37→  return patchElements(`<script>${script}</script>`, { selector: "body", mode: "append" });
38→}
39→
40→export function isSSERequest(request: Request): boolean {
41→  const accept = request.headers.get("accept") || "";
42→  return accept.includes("text/event-stream");
43→}
