13→export function routineDetailPage(
14→  routine: Routine,
15→  exerciseTemplates: ExerciseTemplate[],
16→  currentProgression?: Progression
17→): string {
18→  const parts: string[] = [];
19→
20→  const templateMap = new Map(exerciseTemplates.map((t) => [t.id, t]));
