40→  ${currentProgression.focus ? `<div class="coaching-focus">${escapeHtml(currentProgression.focus)}</div>` : ""}
41→  ${detailsHtml}
42→</div>`);
43→  }
44→
45→  // Exercise list
46→  parts.push(`<div class="section-header">Exercises (${routine.exercises.length})</div>`);
47→
48→  routine.exercises.forEach((routineExercise, index) => {
49→    const template = templateMap.get(routineExercise.exerciseTemplateId);
50→
51→    // Title always comes from the template; fall back to ID if template missing
52→    const title = template?.title ?? routineExercise.exerciseTemplateId;
