  1→export interface AuthResult {
  2→  userId: string;
  3→  email: string;
  4→}
  5→
  6→const CF_ACCESS_CERTS_URL = "https://panesofglass-org.cloudflareaccess.com/cdn-cgi/access/certs";
  7→
  8→interface JWK {
  9→  kid: string;
 10→  kty: string;
 11→  alg: string;
 12→  n: string;
 13→  e: string;
 14→}
 15→
 16→let cachedKeys: Map<string, CryptoKey> | null = null;
 17→let cacheExpiry = 0;
 18→
 19→async function getPublicKeys(): Promise<Map<string, CryptoKey>> {
 20→  const now = Date.now();
 21→  if (cachedKeys && now < cacheExpiry) return cachedKeys;
 22→
 23→  const res = await fetch(CF_ACCESS_CERTS_URL);
 24→  if (!res.ok) throw new Error(`Failed to fetch Access certs: ${res.status}`);
 25→  const data = await res.json() as { keys: JWK[] };
 26→
 27→  const keys = new Map<string, CryptoKey>();
 28→  for (const jwk of data.keys) {
 29→    const key = await crypto.subtle.importKey(
 30→      "jwk",
 31→      jwk,
 32→      { name: "RSASSA-PKCS1-v1_5", hash: "SHA-256" },
 33→      false,
 34→      ["verify"]
 35→    );
 36→    keys.set(jwk.kid, key);
 37→  }
 38→
 39→  cachedKeys = keys;
 40→  cacheExpiry = now + 5 * 60 * 1000; // cache 5 minutes
 41→  return keys;
 42→}
 43→
 44→function base64UrlDecode(str: string): Uint8Array {
 45→  const padded = str.replace(/-/g, "+").replace(/_/g, "/");
 46→  const binary = atob(padded);
 47→  const bytes = new Uint8Array(binary.length);
 48→  for (let i = 0; i < binary.length; i++) {
 49→    bytes[i] = binary.charCodeAt(i);
 50→  }
 51→  return bytes;
 52→}
 53→
 54→async function verifyAndDecode(jwt: string, expectedAud: string): Promise<{ email: string } | null> {
 55→  const parts = jwt.split(".");
 56→  if (parts.length !== 3) return null;
 57→
 58→  const header = JSON.parse(new TextDecoder().decode(base64UrlDecode(parts[0])));
 59→  const payload = JSON.parse(new TextDecoder().decode(base64UrlDecode(parts[1])));
 60→
 61→  // Verify audience
 62→  const aud = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
 63→  if (!aud.includes(expectedAud)) return null;
 64→
 65→  // Verify expiry
 66→  const now = Math.floor(Date.now() / 1000);
 67→  if (payload.exp && payload.exp < now) return null;
 68→
 69→  // Verify signature
 70→  const keys = await getPublicKeys();
 71→  const key = keys.get(header.kid);
 72→  if (!key) return null;
 73→
 74→  const signingInput = new TextEncoder().encode(`${parts[0]}.${parts[1]}`);
 75→  const signature = base64UrlDecode(parts[2]);
 76→
 77→  const valid = await crypto.subtle.verify(
 78→    "RSASSA-PKCS1-v1_5",
 79→    key,
 80→    signature,
 81→    signingInput
 82→  );
 83→
 84→  if (!valid) return null;
 85→
 86→  return { email: payload.email };
 87→}
 88→
 89→export async function getAuthenticatedUser(request: Request, cfAccessAud: string): Promise<AuthResult | null> {
 90→  const jwt = request.headers.get("cf-access-jwt-assertion");
 91→  if (!jwt) return null;
 92→
 93→  try {
 94→    const result = await verifyAndDecode(jwt, cfAccessAud);
 95→    if (!result?.email) return null;
 96→    return { userId: result.email, email: result.email };
 97→  } catch {
 98→    return null;
 99→  }
100→}
101→
102→export async function getAuthenticatedUserOrDev(
103→  request: Request,
104→  env: { ENVIRONMENT: string; CF_ACCESS_AUD?: string }
105→): Promise<AuthResult> {
106→  if (env.CF_ACCESS_AUD) {
107→    const user = await getAuthenticatedUser(request, env.CF_ACCESS_AUD);
108→    if (user) return user;
109→  }
110→  if (env.ENVIRONMENT === "development") {
111→    return { userId: "dev@local", email: "dev@local" };
112→  }
113→  throw new Response("Unauthorized", { status: 403 });
114→}
