 45→+// ──────────────────────────────────────────────────────────────────
 46→+// workout-compare — compare actual Hevy workout data vs prescribed
 47→+// ──────────────────────────────────────────────────────────────────
 48→+
 49→+import type { RoutineExercise } from "../types";
 50→+
 51→+export interface ActualSet {
 52→+  type: "normal" | "warmup" | "dropset" | "failure";
 53→+  reps?: number;
 54→+  weight_kg?: number;
 55→+  duration_seconds?: number;
 56→+  rpe?: number;
 57→+}
 58→+
 59→+export interface ExerciseComparison {
 60→+  exerciseTitle: string;
 61→+  status: "matched" | "extra" | "missing";
 62→+  /** e.g. "3×8" from the routine prescription */
 63→+  prescribedSets?: string;
 64→+  actualSets: ActualSet[];
 65→+}
 66→+
 67→+export interface HevyWorkoutExercise {
 68→+  exercise_template_id: string;
 69→+  title: string;
 70→+  sets: ActualSet[];
 71→+}
 72→+
 73→+/**
 74→+ * Compare actual workout data from Hevy with prescribed sets from the program routine.
 75→+ *
 76→+ * @param actualExercises - parsed from hevy_workout_data JSON (Hevy exercise format)
 77→+ * @param prescribedExercises - from the program routine's exercises array
 78→+ * @param templateMap - maps hevy_template_id → program_template_id
 79→+ */
 80→+export function compareWorkout(
 81→+  actualExercises: HevyWorkoutExercise[],
 82→+  prescribedExercises: RoutineExercise[],
 83→+  templateMap: Map<string, string>
 84→+): ExerciseComparison[] {
 85→+  // Build reverse map: program_template_id → prescribed exercise
 86→+  const prescribedByProgramId = new Map<string, RoutineExercise>(
 87→+    prescribedExercises.map((e) => [e.exerciseTemplateId, e])
 88→+  );
 89→+
 90→+  const result: ExerciseComparison[] = [];
 91→+  const matchedProgramIds = new Set<string>();
 92→+
 93→+  // Process each actual exercise
 94→+  for (const actual of actualExercises) {
 95→+    const programTemplateId = templateMap.get(actual.exercise_template_id);
 96→+    const prescribed = programTemplateId
 97→+      ? prescribedByProgramId.get(programTemplateId)
 98→+      : undefined;
 99→+
100→+    if (prescribed && programTemplateId) {
101→+      matchedProgramIds.add(programTemplateId);
102→+      result.push({
103→+        exerciseTitle: actual.title,
104→+        status: "matched",
105→+        prescribedSets: prescribed.sets,
106→+        actualSets: actual.sets,
107→+      });
108→+    } else {
109→+      result.push({
110→+        exerciseTitle: actual.title,
111→+        status: "extra",
112→+        actualSets: actual.sets,
113→+      });
114→+    }
115→+  }
116→+
117→+  // Add any prescribed exercises that were not performed
118→+  for (const prescribed of prescribedExercises) {
119→+    if (!matchedProgramIds.has(prescribed.exerciseTemplateId)) {
120→+      result.push({
121→+        exerciseTitle: prescribed.exerciseTemplateId,
122→+        status: "missing",
123→+        prescribedSets: prescribed.sets,
124→+        actualSets: [],
125→+      });
126→+    }
127→+  }
128→+
129→+  return result;
130→+}
