 12→  title: string;
 13→  folder_id?: number;
 14→  created_at?: string;
 15→  updated_at?: string;
 16→  exercises: HevyRoutineExercise[];
 17→}
 18→
 19→export interface HevyRoutineExercise {
 20→  exercise_template_id: string;
 21→  sets: HevySet[];
 22→  notes?: string;
 23→}
 24→
 25→export interface HevySet {
 26→  type: "normal" | "warmup" | "dropset" | "failure";
 27→  weight_kg?: number;
 28→  reps: number | null;
 29→  duration_seconds?: number;
 30→}
 31→
 32→export interface HevyWorkout {
 33→  id: string;
 34→  short_id: string;
 35→  title: string;
 36→  start_time: string;
 37→  end_time: string;
 38→  exercises: Array<{
 39→    exercise_template_id: string;
 40→    title: string;
 41→    sets: HevySet[];
 42→  }>;
 43→}
 44→
 45→export class HevyClient {
 46→  private baseUrl = "https://api.hevyapp.com/v1";
 47→  private apiKey: string;
 48→  private static readonly MAX_PAGES = 50;
 49→
 50→  constructor(apiKey: string) {
 51→    this.apiKey = apiKey;
 52→  }
 53→
 54→  private async request<T>(path: string, init?: RequestInit): Promise<T> {
 55→    const url = `${this.baseUrl}${path}`;
 56→    const res = await fetch(url, {
 57→      ...init,
 58→      headers: {
 59→        "api-key": this.apiKey,
 60→        "accept": "application/json",
 61→        "content-type": "application/json",
 62→        ...(init?.headers ?? {}),
 63→      },
 64→    });
 65→
 66→    if (res.status === 429) {
 67→      throw new Error("RATE_LIMITED");
 68→    }
 69→
 70→    if (!res.ok) {
 71→      const errorBody = await res.text().catch(() => "");
 72→      console.error(`Hevy API ${res.status} ${res.statusText} ${url}: ${errorBody}`);
 73→      throw new Error(`Hevy API error: ${res.status} ${res.statusText}: ${errorBody}`);
 74→    }
 75→
 76→    const text = await res.text();
 77→    try {
 78→      return JSON.parse(text) as T;
 79→    } catch {
 80→      console.error(`Hevy API response not JSON (${url}): ${text.slice(0, 200)}`);
 81→      throw new Error(`Hevy API returned non-JSON: ${text.slice(0, 100)}`);
 82→    }
 83→  }
 84→
 85→  async getExerciseTemplates(page = 1, pageSize = 10): Promise<HevyExerciseTemplate[]> {
 86→    const data = await this.request<{ page: number; page_count: number; exercise_templates: HevyExerciseTemplate[] }>(
 87→      `/exercise_templates?page=${page}&pageSize=${pageSize}`
 88→    );
 89→    return data.exercise_templates;
 90→  }
 91→
 92→  async getAllExerciseTemplates(): Promise<HevyExerciseTemplate[]> {
 93→    const all: HevyExerciseTemplate[] = [];
 94→    let page = 1;
 95→    while (page <= HevyClient.MAX_PAGES) {
 96→      const data = await this.request<{ page: number; page_count: number; exercise_templates: HevyExerciseTemplate[] }>(
 97→        `/exercise_templates?page=${page}&pageSize=100`
 98→      );
 99→      all.push(...data.exercise_templates);
100→      if (page >= data.page_count) break;
101→      page++;
102→    }
103→    return all;
104→  }
105→
106→  async getRoutineFolders(): Promise<{ id: number; title: string }[]> {
107→    const all: { id: number; title: string }[] = [];
108→    let page = 1;
109→    while (page <= HevyClient.MAX_PAGES) {
110→      const data = await this.request<{ page: number; page_count: number; routine_folders: { id: number; title: string }[] }>(
111→        `/routine_folders?page=${page}&pageSize=10`
112→      );
113→      all.push(...data.routine_folders);
114→      if (page >= data.page_count) break;
115→      page++;
116→    }
117→    return all;
118→  }
119→
120→  async createRoutineFolder(name: string): Promise<{ id: number; title: string }> {
121→    const data = await this.request<unknown>("/routine_folders", {
122→      method: "POST",
123→      body: JSON.stringify({ routine_folder: { title: name } }),
124→    });
125→    const obj = data as { routine_folder: { id: number; title: string } };
126→    return obj.routine_folder;
127→  }
128→
129→  async getOrCreateRoutineFolder(name: string): Promise<{ id: number; title: string }> {
130→    const folders = await this.getRoutineFolders();
131→    const existing = folders.find((f) => f.title === name);
132→    if (existing) return existing;
133→    return this.createRoutineFolder(name);
134→  }
135→
136→  async createRoutine(routine: { title: string; folder_id?: number; exercises: HevyRoutineExercise[] }): Promise<HevyRoutine> {
137→    const payload = { routine };
138→    const data = await this.request<unknown>("/routines", {
139→      method: "POST",
140→      body: JSON.stringify(payload),
141→    });
142→    // Hevy returns { routine: [ { id, ... } ] }
143→    const obj = data as Record<string, unknown>;
144→    const routines = obj.routine as HevyRoutine[] | undefined;
145→    if (Array.isArray(routines) && routines.length > 0) return routines[0];
146→    throw new Error(`Unexpected createRoutine response: ${JSON.stringify(data).slice(0, 200)}`);
147→  }
148→
149→  async updateRoutine(routineId: string, routine: { title: string; exercises: HevyRoutineExercise[] }): Promise<HevyRoutine> {
150→    const payload = { routine };
151→    const data = await this.request<{ routine: HevyRoutine }>(`/routines/${routineId}`, {
152→      method: "PUT",
153→      body: JSON.stringify(payload),
154→    });
155→    return data.routine;
156→  }
157→
158→  async createExerciseTemplate(template: {
159→    title: string;
160→    exercise_type: string;
161→    equipment_category: string;
162→    muscle_group: string;
163→    other_muscles: string[];
164→  }): Promise<{ id: string }> {
165→    const url = `${this.baseUrl}/exercise_templates`;
166→    const res = await fetch(url, {
167→      method: "POST",
168→      headers: {
169→        "api-key": this.apiKey,
170→        "accept": "application/json",
171→        "content-type": "application/json",
172→      },
173→      body: JSON.stringify({ exercise: template }),
174→    });
175→
176→    if (!res.ok) {
177→      const errorBody = await res.text().catch(() => "");
178→      console.error(`Hevy API ${res.status} ${res.statusText} ${url}: ${errorBody}`);
179→      throw new Error(`Hevy API error: ${res.status} ${res.statusText}: ${errorBody}`);
180→    }
181→
182→    // Hevy returns just the ID as a plain string
183→    const id = await res.text();
184→    return { id: id.trim() };
185→  }
186→
187→  async getAllRoutines(): Promise<HevyRoutine[]> {
188→    const all: HevyRoutine[] = [];
189→    let page = 1;
190→    while (page <= HevyClient.MAX_PAGES) {
191→      const data = await this.request<{ page: number; page_count: number; routines: HevyRoutine[] }>(
192→        `/routines?page=${page}&pageSize=10`
193→      );
194→      all.push(...data.routines);
