117→export default {
118→  async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
119→    try {
120→      const url = new URL(request.url);
121→      const path = url.pathname;
122→      const method = request.method;
123→
124→      // ── POST /api/webhooks/hevy ────────────────────────────────
125→      // Must be checked before auth — this comes from Hevy, not the app user
126→      if (method === "POST" && path === "/api/webhooks/hevy") {
127→        return await handleWebhookEvent(request, env, ctx);
128→      }
129→
130→      const auth = await getAuthenticatedUserOrDev(request, env);
131→      const tz = (request.cf as Record<string, unknown> | undefined)?.timezone as string | undefined;
132→
133→      // ── GET /programs/default.json ─────────────────────────────
134→      if (method === "GET" && path === "/programs/default.json") {
135→        return new Response(JSON.stringify(defaultProgramJson, null, 2), {
136→          headers: {
137→            "content-type": "application/json",
138→            "content-disposition": 'attachment; filename="default-program.json"',
139→          },
140→        });
141→      }
142→
143→      // ── GET / ──────────────────────────────────────────────────
144→      if (method === "GET" && path === "/") {
145→        const user = await getUser(env.DB, auth.userId);
146→        if (!user) {
147→          return htmlResponse(
148→            htmlShell({
149→              title: APP_NAME,
150→              subtitle: "Setup",
151→              body: `<div id="content">${setupPage()}</div>`,
152→            })
153→          );
154→        }
155→
156→        if (isSSERequest(request)) {
157→          return await handleTodaySSE(env, auth.userId, tz);
158→        }
159→
160→        const subtitle = await loadSubtitle(env.DB, auth.userId);
161→        return htmlResponse(
162→          htmlShell({
163→            title: APP_NAME,
164→            subtitle,
165→            activeTab: "today",
166→            ssePath: "/",
167→          })
168→        );
169→      }
170→
171→      // ── GET /progress ──────────────────────────────────────────
172→      if (method === "GET" && path === "/progress") {
173→        if (isSSERequest(request)) {
174→          return await handleProgressSSE(env, auth.userId);
175→        }
176→
177→        const subtitle = await loadSubtitle(env.DB, auth.userId);
178→        return htmlResponse(
179→          htmlShell({
180→            title: "Progress",
181→            subtitle,
182→            activeTab: "progress",
183→            ssePath: "/progress",
184→          })
185→        );
186→      }
187→
188→      // ── GET /program ──────────────────────────────────────────
189→      if (method === "GET" && path === "/program") {
190→        if (isSSERequest(request)) {
191→          return await handleProgramSSE(env, auth.userId);
192→        }
193→
194→        const subtitle = await loadSubtitle(env.DB, auth.userId);
195→        return htmlResponse(
196→          htmlShell({
197→            title: "Program",
198→            subtitle,
199→            activeTab: "program",
200→            ssePath: "/program",
201→          })
202→        );
203→      }
204→
205→      // ── GET /routine/:id ──────────────────────────────────────
206→      const routineMatch = path.match(/^\/routine\/([^/]+)$/);
207→      if (method === "GET" && routineMatch) {
208→        const routineId = decodeURIComponent(routineMatch[1]);
209→
210→        if (isSSERequest(request)) {
211→          return await handleRoutineSSE(env, auth.userId, routineId);
212→        }
213→
214→        return htmlResponse(
215→          htmlShell({
216→            title: "Routine",
217→            activeTab: "today",
218→            ssePath: `/routine/${encodeURIComponent(routineId)}`,
219→          })
220→        );
221→      }
222→
223→      // ── POST /api/validate-program ─────────────────────────────
224→      if (method === "POST" && path === "/api/validate-program") {
225→        return await handleValidateProgram(request);
226→      }
227→
228→      // ── POST /api/validate-import-program ──────────────────────
229→      if (method === "POST" && path === "/api/validate-import-program") {
230→        return await handleValidateImportProgram(request);
231→      }
232→
233→      // ── POST /api/import-program ────────────────────────────────
234→      if (method === "POST" && path === "/api/import-program") {
235→        return await handleImportProgram(request, env, auth.userId, tz);
236→      }
237→
238→      // ── POST /api/setup/:templateId ─────────────────────────────
239→      const setupMatch = path.match(/^\/api\/setup\/([^/]+)$/);
240→      if (method === "POST" && (path === "/api/setup" || setupMatch)) {
241→        const urlTemplateId = setupMatch ? decodeURIComponent(setupMatch[1]) : undefined;
242→        return await handleSetup(request, env, auth.userId, urlTemplateId, tz);
243→      }
244→
245→      // ── POST /api/push-hevy/:id ────────────────────────────────
246→      const pushMatch = path.match(/^\/api\/push-hevy\/([^/]+)$/);
247→      if (method === "POST" && pushMatch) {
248→        const routineId = decodeURIComponent(pushMatch[1]);
249→        return await handlePush(env, auth.userId, routineId);

250→      }
251→
252→      // ── POST /api/pull ─────────────────────────────────────────
253→      if (method === "POST" && path === "/api/pull") {
254→        return await handlePull(env, auth.userId, tz);
255→      }
256→
257→      // ── POST /api/cleanup-routines ───────────────────────────────
258→      if (method === "POST" && path === "/api/cleanup-routines") {
259→        return await handleCleanupRoutines(env, auth.userId);
260→      }
261→
262→      // ── POST /api/complete/:id ─────────────────────────────────
263→      const completeMatch = path.match(/^\/api\/complete\/([^/]+)$/);
264→      if (method === "POST" && completeMatch) {
265→        const itemId = parseInt(completeMatch[1], 10);
266→        return await handleManualComplete(env, auth.userId, itemId, tz);
267→      }
268→
269→      // ── POST /api/webhooks/register ────────────────────────────
270→      if (method === "POST" && path === "/api/webhooks/register") {
271→        return await handleWebhookRegister(request, env, auth.userId, tz);
272→      }
273→
274→      // ── POST /api/webhooks/unregister ──────────────────────────
275→      if (method === "POST" && path === "/api/webhooks/unregister") {
276→        return await handleWebhookUnregister(env, auth.userId, tz);
277→      }
278→
279→      // ── 404 ────────────────────────────────────────────────────
280→      return new Response("Not Found", { status: 404 });
281→    } catch (err) {
282→      if (err instanceof Response) return err;
283→      const message = err instanceof Error ? err.message : "Internal Server Error";
284→      const stack = err instanceof Error ? err.stack : "";
285→      console.error("Unhandled error:", message, stack);
286→      return new Response(message, { status: 500 });
287→    }
288→  },
289→};
