295→/** POST /api/validate-program — validate uploaded JSON, return template cards */
296→async function handleValidateProgram(request: Request): Promise<Response> {
297→  const body = (await request.json()) as Record<string, unknown>;
298→  // Fall back to bundled default program if none uploaded
299→  const programJsonStr = (body.programJson as string | undefined) || JSON.stringify(defaultProgramJson);
