303→    parsed = JSON.parse(programJsonStr);
304→  } catch {
305→    return sseResponse(
306→      patchElements(
307→        `<div class="card"><p style="color:var(--orange)">Invalid JSON file.</p></div>`,
308→        { selector: "#validation-result", mode: "inner" }
309→      )
310→    );
311→  }
312→
313→  const result = validateProgram(parsed);
314→  if (!result.valid) {
315→    const errorList = result.errors
316→      .map((e) => `<li>${escapeHtml(e)}</li>`)
317→      .join("");
318→    return sseResponse(
319→      patchElements(
320→        `<div class="card"><p style="color:var(--orange)">Validation errors:</p><ul style="margin:8px 0 0 16px;font-size:13px;color:var(--text-secondary)">${errorList}</ul></div>`,
321→        { selector: "#validation-result", mode: "inner" }
322→      )
323→    );
324→  }
