922→/** POST /api/cleanup-routines — delete duplicate routines from Hevy */
923→async function handleCleanupRoutines(env: Env, userId: string): Promise<Response> {
924→  const user = await getUser(env.DB, userId);
925→  if (!user || !user.hevy_api_key) {
926→    return sseResponse(
927→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
928→        selector: "#content",
929→        mode: "prepend",
930→      })
931→    );
932→  }
933→
934→  const client = new HevyClient(user.hevy_api_key);
935→  const allRoutines = await client.getAllRoutines();
936→
937→  // Group by title+folder, find duplicates
938→  const byKey = new Map<string, typeof allRoutines>();
939→  for (const r of allRoutines) {
940→    const key = `${r.title}::${r.folder_id ?? "none"}`;
941→    const list = byKey.get(key) ?? [];
942→    list.push(r);
943→    byKey.set(key, list);
944→  }
945→
946→  const toDelete: string[] = [];
947→  for (const [, routines] of byKey) {
948→    if (routines.length > 1) {
949→      // Keep the most recently updated, delete the rest
950→      routines.sort((a, b) => (b.updated_at ?? "").localeCompare(a.updated_at ?? ""));
951→      toDelete.push(...routines.slice(1).map((r) => r.id));
952→    }
953→  }
954→
955→  let deleted = 0;
956→  let failed = 0;
957→  for (const id of toDelete) {
958→    try {
959→      await client.deleteRoutine(id);
960→      deleted++;
961→    } catch {
962→      failed++;
963→    }
964→  }
965→
966→  const msg = toDelete.length === 0
967→    ? "No duplicates found."
968→    : `Cleaned up ${deleted} duplicate(s)${failed > 0 ? `, ${failed} failed` : ""}.`;
969→
970→  return sseResponse(
971→    patchElements(
972→      `<div class="card"><p style="color:var(--green)">${escapeHtml(msg)}</p></div>`,
973→      { selector: "#content", mode: "prepend" }
974→    )
975→  );
976→}
