978→/**
979→ * Core sync logic — fetch recent Hevy workouts, match to pending queue items,
980→ * mark completions, update daily CARs. Reused by both manual pull and webhook.
981→ * Updates last_sync_at on successful completion.
982→ */
983→async function performSync(db: D1Database, userId: string, apiKey: string, tz?: string): Promise<void> {
984→  const program = await loadProgram(db, userId);
985→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
986→  const client = new HevyClient(apiKey);
987→
988→  const [workouts, items] = await Promise.all([
989→    client.getRecentWorkouts(),
990→    getQueueItems(db, userId),
991→  ]);
992→
993→  // Skip workouts already matched to a completed queue item
994→  const usedWorkoutIds = new Set(
995→    items.filter((i) => i.hevy_workout_id).map((i) => i.hevy_workout_id)
996→  );
997→  const newWorkouts = workouts.filter((w) => !usedWorkoutIds.has(w.id));
998→
999→  const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);

1000→
1001→  const nameToRoutineId = new Map<string, string>();
1002→  for (const item of pendingItems) {
1003→    const routine = routineMap.get(item.routine_id);
1004→    if (routine && item.hevy_routine_id) {
1005→      nameToRoutineId.set(routine.title, item.hevy_routine_id);
1006→    }
1007→  }
1008→
1009→  const matches = matchCompletions(
1010→    pendingItems,
1011→    newWorkouts,
1012→    (w) => nameToRoutineId.get(w.title) ?? null
1013→  );
1014→
1015→  // Build workout ID → local date map for accurate completion dates
1016→  const workoutDateMap = new Map<string, string>();
1017→  const workoutExercisesMap = new Map<string, string>();
1018→  for (const w of newWorkouts) {
1019→    const d = tz
1020→      ? new Date(w.start_time).toLocaleDateString("en-CA", { timeZone: tz })
1021→      : w.start_time.slice(0, 10);
1022→    workoutDateMap.set(w.id, d);
1023→    workoutExercisesMap.set(w.id, JSON.stringify(w.exercises));
1024→  }
1025→
1026→  for (const match of matches) {
1027→    const completedDate = workoutDateMap.get(match.workoutId) ?? todayString(tz);
1028→    const workoutData = workoutExercisesMap.get(match.workoutId);
1029→    await markQueueItemCompleted(db, match.queueItemId, completedDate, match.workoutId, workoutData);
1030→  }
1031→
1032→  // Check for daily routine completion (use workout date, not sync date)
1033→  const dailyRoutine = program.routines.find((r) => r.isDaily);
1034→  if (dailyRoutine) {
1035→    const dailyWorkout = workouts.find((w) => w.title === dailyRoutine.title);
1036→    if (dailyWorkout) {
1037→      const workoutDate = tz
1038→        ? new Date(dailyWorkout.start_time).toLocaleDateString("en-CA", { timeZone: tz })
1039→        : dailyWorkout.start_time.slice(0, 10);
1040→      await updateDailyCompleted(db, userId, workoutDate);
1041→    }
1042→  }
1043→
1044→  await updateLastSyncAt(db, userId, new Date().toISOString());
1045→}
