1142→/** POST /api/webhooks/hevy — incoming event from Hevy (no app auth) */
1143→async function handleWebhookEvent(
1144→  request: Request,
1145→  env: Env,
1146→  ctx: ExecutionContext
1147→): Promise<Response> {
1148→  // Extract auth token — Hevy sends it in the Authorization header as "Bearer <token>"
1149→  // or as a plain token. Fall back to checking the request body.
1150→  let authToken: string | null = null;
1151→  const authHeader = request.headers.get("authorization");
1152→  if (authHeader) {
1153→    authToken = authHeader.replace(/^bearer\s+/i, "").trim();
1154→  }
1155→
1156→  if (!authToken) {
1157→    // Try to extract from JSON body
1158→    try {
1159→      const body = await request.clone().json() as Record<string, unknown>;
1160→      if (typeof body.auth_token === "string") {
1161→        authToken = body.auth_token;
1162→      }
1163→    } catch {
1164→      // Body not JSON or already consumed — ignore
1165→    }
1166→  }
1167→
1168→  if (!authToken) {
1169→    return new Response("Unauthorized", { status: 401 });
1170→  }
1171→
1172→  const user = await getUserByWebhookToken(env.DB, authToken);
1173→  if (!user) {
1174→    return new Response("Unauthorized", { status: 401 });
1175→  }
1176→
1177→  // Acknowledge immediately — Hevy expects a fast 2xx
1178→  // Run sync in the background via waitUntil so the response is not delayed
1179→  if (user.hevy_api_key) {
1180→    ctx.waitUntil(
1181→      performSync(env.DB, user.id, user.hevy_api_key).catch((err) => {
1182→        console.error("Webhook sync failed for user", user.id, err instanceof Error ? err.message : err);
1183→      })
1184→    );
1185→  }
1186→
1187→  return new Response(null, { status: 200 });
1188→}
