 1→export function escapeHtml(str: string): string {
 2→  return str
 3→    .replace(/&/g, "&amp;")
 4→    .replace(/</g, "&lt;")
 5→    .replace(/>/g, "&gt;")
 6→    .replace(/"/g, "&quot;");
 7→}
 8→
 9→export function escapeAttr(str: string): string {
10→  return str.replace(/[&<>"']/g, (c) => {
11→    switch (c) {
12→      case "&": return "&amp;";
13→      case "<": return "&lt;";
14→      case ">": return "&gt;";
15→      case '"': return "&quot;";
16→      case "'": return "&#39;";
17→      default: return c;
18→    }
19→  });
20→}
21→
22→export function truncate(str: string, max: number): string {
23→  if (str.length <= max) return str;
24→  const cut = str.lastIndexOf(" ", max);
25→  return (cut > 0 ? str.slice(0, cut) : str.slice(0, max)) + "\u2026";
26→}
