610→ * sync to Hevy (exercise templates + routines), then generate queue.
611→ * Reused by both initial setup (handleSetup) and program import (handleImportProgram).
612→ */
613→async function activateProgram(
614→  db: D1Database,
615→  userId: string,
616→  program: Program,
617→  programJsonStr: string,
618→  templateId: string,
619→  apiKey: string | undefined
620→): Promise<void> {
621→  const template = program.weekTemplates.find((t) => t.id === templateId)!;
622→
623→  // 1. Clear existing pending queue items and mappings (preserve completed history)
624→  await clearPendingQueueItems(db, userId);
625→  await clearMappings(db, userId);
626→
627→  // 2. Insert program (deactivates previous via batch in insertProgram)
628→  await insertProgram(db, userId, programJsonStr);
629→
630→  // 3. Hevy exercise template & routine creation (only with API key)
631→  const routineIdMap = new Map<string, string>();
632→  if (apiKey) {
633→    const client = new HevyClient(apiKey);
634→
635→    // b. Fetch all Hevy exercise templates
636→    const hevyTemplates = await client.getAllExerciseTemplates();
637→
638→    // c. Auto-match our templates to Hevy's by normalized title
639→    const matched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
640→
641→    // d. Create custom Hevy exercise templates for unmatched
642→    const customCreated = new Set<string>();
643→    for (const et of program.exerciseTemplates) {
644→      if (!matched.has(et.id)) {
645→        const enums = mapToHevyEnums(et);
646→        const created = await client.createExerciseTemplate({
647→          title: et.title,
648→          exercise_type: enums.exerciseType,
649→          equipment_category: enums.equipmentCategory,
650→          muscle_group: enums.primaryMuscleGroup,
