async function handleProgramSSE(env: Env, userId: string): Promise<Response> {
  let program: Program;
  let user: Awaited<ReturnType<typeof getUser>>;
  try {
    [program, user] = await Promise.all([
      loadProgram(env.DB, userId),
      getUser(env.DB, userId),
